// savedQueryURL builds the round-trip URL for a saved query — the
// surface-specific list page with the captured params re-encoded.
// Mirrors console.EncodeSavedQueryURL but lives in views so the templ
// doesn't reach into the console package.
func savedQueryURL(q pg.SavedQuery) string {
	v := url.Values{}
	for k, val := range q.Params {
		v.Set(k, val)
	}
	enc := v.Encode()
	base := "/" + string(q.Surface)
	if enc == "" {
		return base
	}
	return base + "?" + enc
}

// savedQueryParamsLabel renders a short preview of the saved params
// for the inventory table's params column. Stops at 80 chars to keep
// the row a single line.
func savedQueryParamsLabel(q pg.SavedQuery) string {
	if len(q.Params) == 0 {
		return "(none)"
	}
	parts := make([]string, 0, len(q.Params))
	for k, v := range q.Params {
		if v == "" {
			parts = append(parts, k)
			continue
		}
		parts = append(parts, k+"="+v)
	}
	out := strings.Join(parts, " ")
	if len(out) > 80 {
		out = out[:77] + "..."
	}
	return out
}

