func dashboardCardCountLabel(d pg.Dashboard) string {
	switch len(d.Cards) {
	case 0:
		return "(empty)"
	case 1:
		return "1 card"
	}
	return cardCountStr(len(d.Cards))
}

func cardCountStr(n int) string {
	// Inline formatter to avoid pulling strconv into the templ.
	digits := []byte{}
	if n == 0 {
		return "0 cards"
	}
	for n > 0 {
		digits = append([]byte{byte('0' + n%10)}, digits...)
		n /= 10
	}
	return string(digits) + " cards"
}

